package ru.memearena.media.application;
import org.junit.jupiter.api.Test; import ru.memearena.error.ApiException; import static org.junit.jupiter.api.Assertions.*;
class ImageInspectorTest { @Test void jpeg(){ImageInspector.validate("image/jpeg",new byte[]{(byte)0xff,(byte)0xd8,(byte)0xff,1});} @Test void png(){ImageInspector.validate("image/png",new byte[]{(byte)0x89,0x50,0x4e,0x47,0x0d,0x0a,0x1a,0x0a});} @Test void gif(){ImageInspector.validate("image/gif","GIF89ax".getBytes());} @Test void webp(){ImageInspector.validate("image/webp","RIFFxxxxWEBP".getBytes());} @Test void fakeRejected(){assertThrows(ApiException.class,()->ImageInspector.validate("image/png",new byte[]{1,2,3}));} @Test void sha(){assertEquals("2cf24dba5fb0a30e26e83b2ac5b9e29e1b161e5c1fa7425e73043362938b9824",ImageInspector.sha256("hello".getBytes()));} }
